{
  "serverName": "petstore-mcp",
  "serverDescription": "MCP server for the Swagger Petstore API: list, create, fetch, update, and delete pets.",
  "tools": [
    {
      "sourceName": "listPets",
      "toolName": "list_pets",
      "title": "List pets",
      "description": "List pets, optionally filtered by tags and limited in count.",
      "group": "pets"
    },
    {
      "sourceName": "createPet",
      "toolName": "create_pet",
      "title": "Create pet",
      "description": "Create a new pet from the provided details.",
      "group": "pets"
    },
    {
      "sourceName": "showPetById",
      "toolName": "show_pet_by_id",
      "title": "Show pet by id",
      "description": "Fetch a single pet by its id.",
      "group": "pets"
    },
    {
      "sourceName": "updatePet",
      "toolName": "update_pet",
      "title": "Update pet",
      "description": "Replace an existing pet identified by id.",
      "group": "pets"
    },
    {
      "sourceName": "deletePet",
      "toolName": "delete_pet",
      "title": "Delete pet",
      "description": "Delete a pet by its id.",
      "group": "pets"
    }
  ]
}
